    //刷新控件css区块
    nsmart.refreshCurControlCssTag = function (smartView, cssTemplate) {
        cssTemplate = cssTemplate || $('#currentcsstemplate').html();
        for (var key in smartView.controlData.Css) {
            if (key === "$StyleItemAndColor") {
                var tempKey = '#{\\' + key + '}';
                cssTemplate = nsmart.replaceAll(cssTemplate, tempKey, smartView.controlData.Css[key], false);
            } else {
                if (key.indexOf('$') == 0) {
                    var tmpKey = "\\" + key;
                    cssTemplate = nsmart.replaceAll(cssTemplate, tmpKey, smartView.controlData.Css[key], false);
                }
            }
        }
        cssTemplate = nsmart.replaceAll(cssTemplate, "&gt;", ">", false);
        smartView.refreshCssTag(cssTemplate);
    }
    nsmart.changeCurCssValue = function (key, value) {
        nsmart.changeCssValue(nsmart.getCurrentEditControlId(), key, value);
    }
    nsmart.changeCssValue = function (controlId, key, value) {
        var smartView = nsmart.getSmartView(controlId);
        switch (key) {
            case "background-clear":
                break;
            case "mustache-fresh":
                break;
            default:
                smartView.setCss(key, value, null);
                break;
        }
        console.log('"' + key + '":"' + value + '",');
        var cssTemplate = $('#currentcsstemplate').html();
        for (var key in smartView.controlData.Css) {
            if (key === "$StyleItemAndColor") {
                var tempKey = '#{\\' + key + '}';
                cssTemplate = nsmart.replaceAll(cssTemplate, tempKey, smartView.controlData.Css[key], false);
            } else {
                if (key.indexOf('$') == 0) {
                    var tmpKey = "\\" + key;
                    cssTemplate = nsmart.replaceAll(cssTemplate, tmpKey, smartView.controlData.Css[key], false);
                }
            }
        }
        cssTemplate = nsmart.replaceAll(cssTemplate, "&gt;", ">", false);
        smartView.refreshCss();
        smartView.refreshCssTag(cssTemplate);
    }
    nsmart.batchChangeCssValue = function (controlId, itemArray) {
        if (typeof (itemArray) != 'undefined' && itemArray.length > 0) {
            var smartView = nsmart.getSmartView(controlId);
            var arrayLen = itemArray.length;
            for (var i = 0; i < arrayLen; i++) {
                var item = itemArray[i];
                smartView.setCss(item.key, item.value, null);
            }
            var cssTemplate = $('#currentcsstemplate').html();
            for (var key in smartView.controlData.Css) {
                if (key === "$StyleItemAndColor") {
                    var tempKey = '#{\\' + key + '}';
                    cssTemplate = nsmart.replaceAll(cssTemplate, tempKey, smartView.controlData.Css[key], false);
                } else {
                    if (key.indexOf('$') == 0) {
                        var tmpKey = "\\" + key;
                        cssTemplate = nsmart.replaceAll(cssTemplate, tmpKey, smartView.controlData.Css[key], false);
                    }
                }
            }
            cssTemplate = nsmart.replaceAll(cssTemplate, "&gt;", ">", false);
            smartView.refreshCss();
            smartView.refreshCssTag(cssTemplate);
        }
    }
