    nsmart.replaceAll = function (source, wreplace, replaceWith, ignoreCase) {
        if (!RegExp.prototype.isPrototypeOf(wreplace)) {
            var result = source.replace(new RegExp(wreplace, (ignoreCase ? "gi" : "g")), replaceWith);
            return result;
        } else {
            var result = source.replace(wreplace, replaceWith);
            return result;
        }
    }
    /*绑定控件切换样式控件*/
    nsmart.bindChangeStyleEvent = function () {
        var currentControlType = document.getElementById('pcontrolType').value;
        var temppanel = $("#widgetpanellist " + ($("#widgetlist li[data-role='" + currentControlType + "']").find("a").attr("data-content"))).find(".m-widget-template");
        if (temppanel.length == 0) {
            var spClass = "x-" + currentControlType;
            var temppanel = $("#widgetpanellist ." + spClass).closest(".m-widget-template").clone();
            temppanel.find(".u-widget-temContent,.u-widget-temTitle").not("." + spClass).remove();
            var url = temppanel.find(".u-widget-temTitle." + spClass).find('a').attr('href');
            if (url == undefined || url == "#") {
                $('#layer-style-change .modal-close.f-mr10').hide();
            }
            else {
                $('#layer-style-change .modal-close.f-mr10').attr('href', url);
                $('#layer-style-change .modal-close.f-mr10').attr('target', "_blank");
            }
            temppanel.find(".u-widget-temTitle." + spClass).remove();
        }
        else {
            var url = temppanel.prev().find('.icon-help-blockInfo').parent().attr('href');
            if (url == undefined || url == "#") {
                $('#layer-style-change .modal-close.f-mr10').hide();
            }
            else {
                $('#layer-style-change .modal-close.f-mr10').attr('href', url);
                $('#layer-style-change .modal-close.f-mr10').attr('target', "_blank");
            }
        }
        if (temppanel.find(".controlKey").length > 1) {
            $("#change-select-btn").click(function () {
                $("#StyleTemp").html(temppanel.html());

                $("#StyleTemp").find("img").each(function () {
                    $(this).attr("src", $(this).attr("data-original"));
                });
                $("#StyleTemp").find(".f-scrollbar").lzscroll();
                $("#StyleTemp .controlKey").click(function () {
                    if ($(this).attr('data-key') == undefined) {
                        return;
                    }
                    var control = $(this).attr('data-key').split(":");
                    if (control.length != 4 && control.length != 5) {
                        alert("控件配置错误");
                        return;
                    }
                    var controlId = document.getElementById('pcontrolId').value;
                    var currentStyle = document.getElementById('pcontrolStyle').value;
                    var currentColor = document.getElementById('pcontrolColor').value;
                    var viewType = control[1];
                    var style = control[2];
                    var color = control[3];
                    var themeColor = "";
                    if (control.length == 5) {
                        themeColor = control[4];
                    }
                    if (style === currentStyle) {
                        if (color == currentColor) {
                            nsmart.changeSmartViewThemeColor(controlId, themeColor);
                        } else {
                            $("#StyleTemp").find('.u-colimg').removeClass('z-current');
                            $(this).find('.u-colimg').addClass('z-current');
                            nsmart.changeSmartViewColor(controlId, color, function () {
                                nsmart.changeSmartViewThemeColor(controlId, themeColor);
                            });
                            document.getElementById('pcontrolColor').value = color;
                        }
                    } else {
                        $("#StyleTemp").find('.u-colimg').removeClass('z-current');
                        $(this).find('.u-colimg').addClass('z-current');
                        nsmart.changeSmartViewStyle(controlId, style, color, function () {
                            if (viewType === 'image') {
                                // 遮罩数据初始化
                                nsmart.changeCurViewData('ClipPictureData', '');
                                nsmart.changeCurViewData('hasCliped', '');
                            }
                            var smartView = nsmart.getCurSmartView();
                            if (smartView && (typeof smartView.changeStyleAfterCallback == 'function')) {
                                smartView.changeStyleAfterCallback()
                            }
                            nsmart.changeSmartViewThemeColor(controlId, themeColor);
                        });
                        document.getElementById('pcontrolColor').value = color;
                        document.getElementById('pcontrolStyle').value = style;
                    }
                    $("#layer-style-change").hide();
                });
                var currentStyle = $('#pcontrolStyle').val();
                var currentColor = $('#pcontrolColor').val();
                var currentThemeColor = nsmart.getCurSmartView().controlData.Css.themeColorName;

                $("#StyleTemp .controlKey[data-key='basic:" + currentControlType + ":" + currentStyle + ":" + currentColor + "']").unbind("click").find(".u-colimg").addClass("z-current");
                if (currentThemeColor) {
                    $("#StyleTemp .controlKey[data-key='basic:" + currentControlType + ":" + currentStyle + ":" + currentColor + ":" + currentThemeColor + "']").unbind("click").find(".u-colimg").addClass("z-current");
                }
                $("#layer-style-change").show();
                $.lzprompt();
            });
        } else {
            $("#change-select-btn .lzdesigner-panel-cut-style").hide();
        }
    }
    /*控件工具栏显示选项 -- 是否显示切换样式icon*/
