                                sv.$control.find('.ui-resizable-nw').addClass('ui-hide-handler');
                                sv.$control.find('.ui-resizable-ne').addClass('ui-hide-handler');
                                sv.$control.find('.ui-resizable-w').addClass('ui-hide-handler');
