    nsmart.setSmartViewFixedToAbs = function (positionType, fixedType, smartView, foffsetX, foffsetY) {
        smartView.$control.find('.ui-resizable-handle').removeClass('ui-hide-handler');
        smartView.$control.css({ 'position': positionType });
        smartView.setCss("position", positionType, null);
        smartView.setCss('fixedPosition', 'None');
        if (smartView.$control.attr('ctype') === 'banner' && smartView.$control.attr('cstyle') === 'Style2') {
            smartView.$control.css({ 'height': '100%' });
        }
        var offsetX = foffsetX, offsetY = foffsetY;
        smartView.$control.css({ 'left': offsetX + 'px', 'top': offsetY + 'px', 'right': 'auto', 'bottom': 'auto' });
        smartView.enableDrag();
        smartView.setPosition(offsetX, offsetY);
    }
    nsmart.getFixedSmartAbsPosition = function (fixedType, view, foffsetX, foffsetY) {
        var position = {};
        var $window = $(window);
        switch (fixedType) {
            case 'TopLeft':
                position.left = foffsetX;
                position.top = foffsetY;
                break;
            case 'TopCenter':
                position.left = parseInt($window.width() / 2 - view.width() / 2 + foffsetX, 10);
                position.top = foffsetY;
                break;
            case 'TopRight':
                position.left = parseInt($window.width() - view.width() - foffsetX);
                position.top = foffsetY;
                break;
            case 'LeftCenter':
                position.left = foffsetX;
                position.top = parseInt($window.height() / 2 - view.height() / 2 + foffsetY, 10);
                break;
            case 'RightCenter':
                position.left = parseInt($window.width() - view.width() - foffsetX, 10);
                position.top = parseInt($window.height() / 2 - view.height() / 2 + foffsetY, 10);
                break;
            case 'BottomLeft':
                position.left = foffsetX;
                position.top = $window.height() - view.height() - foffsetY;
                break;
            case 'BottomCenter':
                position.left = parseInt($window.width() / 2 - view.width() / 2 + foffsetX, 10);
                position.top = parseInt($window.height() - view.height() - foffsetY, 10);
                break;
            case 'BottomRight':
                position.left = parseInt($window.width() - view.width() - foffsetX, 10);
                position.top = parseInt($window.height() - view.height() - foffsetY, 10);
                break;
            default:
                position.left = 0;
                position.top = 0;
                break;
        }
        return position;
    }
