    nsmart.htmlEncode = function (c) {
        var s = "";
        if (c.length == 0) return "";
        s = c.replace(/&/g, "&amp;");
        s = s.replace(/</g, "&lt;");
        s = s.replace(/>/g, "&gt;");
        s = s.replace(/ /g, "&nbsp;");
        s = s.replace(/\'/g, "&#39;");
        s = s.replace(/\"/g, "&quot;");
        return s;
    }
    nsmart.htmlDecode = function (c) {
        var s = "";
        if (c.length == 0) return "";
        s = c.replace(/&amp;/g, "&");
        s = s.replace(/&lt;/g, "<");
        s = s.replace(/&gt;/g, ">");
        s = s.replace(/&nbsp;/g, " ");
        s = s.replace(/&#39;/g, "\'");
        s = s.replace(/&quot;/g, "\"");
        return s;
    }
    nsmart.createHierarchicalHtml = function (smartArray, pvid, layer) {
        var self = this;
        var html = "";
        var subHtml = "";
        var smartType = "";
        var smartName = "";
        var parentId = "";
        var smartId = "";
        $.each(smartArray, function (index, element) {
            var el = $(element);
            if (!el.hasClass("smart-deleted") && el.attr("pvid") == pvid) {
                smartType = el.attr("ctype");
                if (smartType != "dialog") {
                    smartName = nsmart.getControlName(smartType, el.attr("cstyle"));
                    parentId = el.attr("id");
                    smartId = el.attr("id");
                    html += "<li class='u-layer-content' smartcontrolid='" + smartId + "'><div class='u-layer-item' data-lzlayer='" + layer + "'><span class='layer-delete lzprompt-bottom f-right' data-lztitle='删除'><i class='icon icon-delete'></i></span><span class='layer-pic f-left'></span><span class='layer-img f-left'><img src='/static/Widgetimg/Hierarchical/" + smartType + ".png'></span><a class='layer-txt' href='javascript:;'>" + smartName + "</a></div>";
                    subHtml = self.createHierarchicalHtml(smartArray, parentId.substring(4, parentId.length), layer + 1);
                    if (subHtml != "") {
                        html = html + "<ul class='u-layer'>" + subHtml + "</ul>";
                    }
                    html = html + "</li>";
                }
            }
        });
        return html;
    }
    nsmart.selectSmartView = function (controlId) {
        var anchorControlId = this.openSmartView(controlId);
        var $mainFrame = nsmart.childContent();
        var element = $mainFrame.find('#' + controlId);
        var anchorControl = $mainFrame.find('#' + anchorControlId);
        var top = $(anchorControl).offset().top;
        top = top - 30;
        if ($mainFrame.find("#mobileDesign_scrollbar").length > 0) //移动端
        {
            var mianFrameWindow = nsmart.childWindow();
            mianFrameWindow.smartControlScrollTop(top);
        }
        else //pc端
        {
            $mainFrame.find("html").scrollTop(top);
            $mainFrame.find("body").scrollTop(top);
        }
        $(element).click();
    }
    nsmart.openSmartView = function (controlId) {
        var $mainFrame = nsmart.childContent();
        var element = $mainFrame.find('#' + controlId);
        var areaId = element.attr("areaid");
        var parentId = element.attr("pvid");
        var isMobile = $mainFrame.find("#mobileDesign_scrollbar").length > 0;
        var result = controlId;
        if (typeof parentId != 'undefined' && parentId != "" && typeof areaId != 'undefined' && areaId != "") {
            parentId = "smv_" + parentId;
            var parentControl = $mainFrame.find("#" + parentId).first();
            if (parentControl.length > 0) {
                var ctype = parentControl.attr("ctype");
                var cstyle = parentControl.attr("cstyle");
                if (ctype == "tab") {
                    if (isMobile) {
                        parentControl.find(".mw-label-tips li[data-area='" + areaId + "']").click();
                    }
                    else {
                        if (cstyle == "Style6") {
                            var targetli = parentControl.find(".w-label-tips li[data-area='" + areaId + "']");
                            if (targetli.length > 0) {
                                targetli.siblings().removeClass("current");
                                targetli.addClass("current");
                                targetli.prev().addClass("current");
                                targetli.next().addClass("current");
                            }
                            targetli = parentControl.find(".w-label-content li[data-area='" + areaId + "']");
                            if (targetli.length > 0) {
                                targetli.siblings().removeClass("current");
                                targetli.addClass("current");
                                parentControl.find(".w-label-content").show();
                            }
                        }
                        else {
                            parentControl.find(".w-label-tips li[data-area='" + areaId + "']").first().click();
                        }

                    }
                }
                else if (ctype == "slideset") {
                    var $$ = nsmart.childWindow().$;
                    var dataArray = nsmart.childContent().find('#' + parentId);
                    var $curBox = $mainFrame.find("#" + parentId).find("#" + controlId).closest(".content-box");
                    var index = $curBox.index();
                    var sliderset = $$.data(dataArray[0], 'jssor_slide');
                    if (typeof sliderset != 'undefined') {
                        sliderset.$GoTo(index - 1);
                        $mainFrame.find("#" + parentId).find(".w-control-text .page").text(index);
                        $curBox.find(".smAreaC").css("display", "block");
                        $curBox.find(".animated").css("opacity", 1);
                    }
                }
                else if (ctype == "fullpage") {
                    var href = nsmart.childWindow().location.href;
                    if (cstyle == "Style1") {
                        var index = $mainFrame.find("#" + parentId).find("#" + controlId).closest(".fp-section").index();
                        index = index + 1;
                        var pindex = href.indexOf("#");
                        if (pindex > -1) {
                            href = href.substring(0, pindex);
                        }
                        href = href + "#" + "sec_" + parentId.substr(4) + "_" + index;
                        nsmart.childWindow().location.href = href;
                    }
                    else if (cstyle == "Style2") {
                        var index = $mainFrame.find("#" + parentId).find("#" + controlId).closest(".fp-table").index();
                        var pindex = href.indexOf("#");
                        if (pindex > -1) {
                            href = href.substring(0, pindex);
                        }
                        href = href + "#" + "sec_" + parentId.substr(4);
                        href = href + "/" + "sec_" + parentId.substr(4) + "_" + areaId;
                        nsmart.childWindow().location.href = href;
                    }

                }
                result = this.openSmartView(parentId);
            }
        }

        return result;
    }
