        // if(ctype === "dialog" && cstyle === "Style2"){
        //     const controlHeight = $control.height();
        //     if (isNaN(controlHeight)) {
        //         throw new Error('控件高度获取失败，请检查元素可见性');
        //     }
        //     $('#rightEditContainer').css('top', (i, oldTop) => {
        //         const currentTop = parseInt(oldTop, 10) || 0;
        //         return `${currentTop - controlHeight}px`;
        //     });

        // }
